import{_ as a,c as r,o as t,ak as s,am as o}from"./chunks/framework.BZBtq1Ev.js";const f=JSON.parse('{"title":"AireFlow Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireflow-v2-39-0.md","filePath":"aireblock-releases/aireflow-v2-39-0.md","lastUpdated":1777564046000}'),i={name:"aireblock-releases/aireflow-v2-39-0.md"};function l(n,e,d,h,c,p){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="aireflow-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+o+'"> AireFlow Release Notes</span> <a class="header-anchor" href="#aireflow-release-notes" aria-label="Permalink to “AireFlow Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 2.39.0<br><strong>Release Date:</strong> 6th May 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Task-Level Input Context (FLOW-1289)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Upgraded Unsupported GraphQL Framework (FLOW-1316)</li><li>GraphQL Alias Overloading Protection (FLOW-1317)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="task-level-input-context-flow-1289" tabindex="-1">Task-Level Input Context (FLOW-1289) <a class="header-anchor" href="#task-level-input-context-flow-1289" aria-label="Permalink to “Task-Level Input Context (FLOW-1289)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>It is now possible to define example input context at the task level, in addition to the existing workflow-level setting. Task-level context takes precedence when set, enabling more accurate and relevant previews for individual tasks within a workflow.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now configure example data specific to each task, so previews reflect the real context of that task rather than relying on a single shared workflow example. This makes it much easier to design and test tasks that depend on particular input values.</p></div><hr><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="upgraded-unsupported-graphql-framework-flow-1316" tabindex="-1">Upgraded Unsupported GraphQL Framework (FLOW-1316) <a class="header-anchor" href="#upgraded-unsupported-graphql-framework-flow-1316" aria-label="Permalink to “Upgraded Unsupported GraphQL Framework (FLOW-1316)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The GraphQL framework (Chilli Cream Hot Chocolate) running on the AireFlow API was found to be on an end-of-life version that no longer receives security patches, as identified during penetration testing. The framework has been upgraded to a current supported version.</p></div><hr><h4 id="graphql-alias-overloading-protection-flow-1317" tabindex="-1">GraphQL Alias Overloading Protection (FLOW-1317) <a class="header-anchor" href="#graphql-alias-overloading-protection-flow-1317" aria-label="Permalink to “GraphQL Alias Overloading Protection (FLOW-1317)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The AireFlow GraphQL API was found to be vulnerable to alias overloading, where repeated aliases in a single query could be used to overwhelm server resources. Server-side restrictions on the number of aliases permitted per query have been applied to address this.</p></div>',22)])])}const m=a(i,[["render",l]]);export{f as __pageData,m as default};
